+    /// without parent-child relationships.
+    /// </summary>
+    public event Action? OnAlertDataChanged;
+
+    /// <summary>
+    /// Simulates a database query that returns the number of items
+    /// below minimum stock levels for the given warehouse.
+    /// </summary>
+    public Task<int> GetLowStockCountAsync(string warehouseId)
+    {
+        var count = _random.Next(0, 16);
+        return Task.FromResult(count);
+    }
+
+    /// <summary>
+    /// Fetches fresh data and notifies all subscribers.
+    /// Called by whichever component owns the polling loop.
+    /// </summary>
+    public async Task RefreshAsync(string warehouseId)
+    {
+        _lastLowStockCount = await GetLowStockCountAsync(warehouseId);
+        OnAlertDataChanged?.Invoke();
+    }
+}
