namespace sv_079d17ec572e40418b59f6579fa6ad78.Services;

public sealed class WarehouseStateService
{
    public record Warehouse(string Id, string Name);

    public static readonly IReadOnlyList<Warehouse> AvailableWarehouses =
    [
        new("wh-a", "Warehouse A"),
        new("wh-b", "Warehouse B"),
        new("wh-c", "Warehouse C"),
        new("wh-d", "Warehouse D"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Fired when the selected warehouse changes.
    /// Subscribers must call InvokeAsync/StateHasChanged on the UI thread.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        if (AvailableWarehouses.All(w => w.Id != warehouseId)) return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

