toolArgs.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@using sv_079d17ec572e40418b59f6579fa6ad78.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard - @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 28rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock items:
            <span class="badge @(AlertService.LastLowStockCount > 0 ? "bg-danger" : "bg-success") fs-6">
                @AlertService.LastLowStockCount
            </span>
        </p>
        <p class="text-muted small mb-0">
            Polling every 10 seconds. Last check: @_lastPoll.ToString("T")
        </p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime _lastPoll = DateTime.Now;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertDataChanged += HandleAlertDataChanged;

        // Initial fetch
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastPoll = DateTime.Now;

        StartPolling();
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
                _lastPoll = DateTime.Now;
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async void HandleWarehouseChanged()
    {
        // Restart polling for the new warehouse and do an immediate refresh.
        StartPolling();
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        _lastPoll = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private void HandleAlertDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertDataChanged -= HandleAlertDataChanged;
        StopPolling();
    }
}

